assert len(PROMPTS) == 1000, f"Expected 1000 prompts, got {len(PROMPTS)}"


def run_regression():
    c1 = CavemanCompressor(level=1)
    c2 = CavemanCompressor(level=2)
    c3 = CavemanCompressor(level=3)

    # --- Accumulators ---
    total = len(PROMPTS)
    crashes = []
    empty_outputs = []
    monotonic_failures = []       # higher level saves FEWER tokens
    semantic_failures = []        # manual heuristic checks
    savings_by_level = {1: [], 2: [], 3: []}
    pct_by_level = {1: [], 2: [], 3: []}

    for i, prompt in enumerate(PROMPTS):
        idx = i + 1
        try:
            r1, s1 = c1.compress(prompt, verbose=True)
            r2, s2 = c2.compress(prompt, verbose=True)
            r3, s3 = c3.compress(prompt, verbose=True)
        except Exception as e:
            crashes.append((idx, prompt[:80], str(e)))
            continue

        # --- Empty output check ---
        for lvl, result in [(1, r1), (2, r2), (3, r3)]:
            if not result or not result.strip():
                empty_outputs.append((idx, lvl, prompt[:80]))

        # --- Monotonic savings check ---
        # Level 2 must save >= level 1, level 3 >= level 2
        if s2["saved_tokens"] < s1["saved_tokens"]:
            monotonic_failures.append({
                "idx": idx,
                "prompt": prompt[:100],
                "issue": f"L2 saves {s2['saved_tokens']} < L1 saves {s1['saved_tokens']}",
                "l1_saved": s1["saved_tokens"],
                "l2_saved": s2["saved_tokens"],
                "l1_result": r1[:120],
                "l2_result": r2[:120],
            })
        if s3["saved_tokens"] < s2["saved_tokens"]:
            monotonic_failures.append({
                "idx": idx,
                "prompt": prompt[:100],
                "issue": f"L3 saves {s3['saved_tokens']} < L2 saves {s2['saved_tokens']}",
                "l2_saved": s2["saved_tokens"],
                "l3_saved": s3["saved_tokens"],
                "l2_result": r2[:120],
                "l3_result": r3[:120],
            })

        # --- Semantic preservation heuristics ---
        # Check that key content words from the original survive in compressed output
        # We check level 3 (most aggressive) — if it passes, levels 1 and 2 are fine
        semantic_issues = check_semantic_preservation(prompt, r1, r2, r3)
        if semantic_issues:
            semantic_failures.append({
                "idx": idx,
                "prompt": prompt[:120],
                "issues": semantic_issues,
                "l1": r1[:150],
                "l2": r2[:150],
                "l3": r3[:150],
            })

        # --- Accumulate savings ---
        for lvl, stats in [(1, s1), (2, s2), (3, s3)]:
            savings_by_level[lvl].append(stats["saved_tokens"])
            pct_by_level[lvl].append(stats["saved_pct"])

    # --- Print Report ---
    print("=" * 72)
    print(f"CAVEMAN COMPRESSOR REGRESSION TEST — {total} prompts")
    print("=" * 72)

    print(f"\n--- CRASHES: {len(crashes)} ---")
    for idx, snippet, err in crashes:
        print(f"  #{idx}: {snippet}... => {err}")

    print(f"\n--- EMPTY OUTPUTS: {len(empty_outputs)} ---")
    for idx, lvl, snippet in empty_outputs[:20]:
        print(f"  #{idx} L{lvl}: {snippet}...")

    print(f"\n--- MONOTONIC SAVINGS VIOLATIONS: {len(monotonic_failures)} ---")
    for f in monotonic_failures[:30]:
        print(f"  #{f['idx']}: {f['issue']}")
        print(f"    Prompt: {f['prompt']}")
        if "l1_result" in f:
            print(f"    L1 result: {f.get('l1_result', 'N/A')}")
            print(f"    L2 result: {f.get('l2_result', 'N/A')}")
        if "l2_result" in f and "l3_result" in f:
            print(f"    L2 result: {f['l2_result']}")
            print(f"    L3 result: {f['l3_result']}")
    if len(monotonic_failures) > 30:
        print(f"  ... and {len(monotonic_failures) - 30} more")

    print(f"\n--- SEMANTIC PRESERVATION FAILURES: {len(semantic_failures)} ---")
    for f in semantic_failures[:30]:
        print(f"  #{f['idx']}: {', '.join(f['issues'])}")
        print(f"    Prompt: {f['prompt']}")
        print(f"    L3:    {f['l3']}")
    if len(semantic_failures) > 30:
        print(f"  ... and {len(semantic_failures) - 30} more")

    # --- Summary stats ---
    print("\n" + "=" * 72)
    print("SAVINGS STATISTICS")
    print("=" * 72)
    for lvl in [1, 2, 3]:
        savings = savings_by_level[lvl]
        pcts = pct_by_level[lvl]
        if not savings:
            continue
        avg_saved = sum(savings) / len(savings)
        avg_pct = sum(pcts) / len(pcts)
        min_pct = min(pcts)
        max_pct = max(pcts)
        zero_savings = sum(1 for s in savings if s <= 0)
        negative_savings = sum(1 for s in savings if s < 0)
        print(f"\n  Level {lvl}:")
        print(f"    Avg tokens saved:  {avg_saved:.1f}")
        print(f"    Avg % reduction:   {avg_pct:.1f}%")
        print(f"    Min % reduction:   {min_pct}%")
        print(f"    Max % reduction:   {max_pct}%")
        print(f"    Zero savings:      {zero_savings}/{total}")
        print(f"    Negative savings:  {negative_savings}/{total}")

    # --- Overall verdict ---
    total_issues = len(crashes) + len(empty_outputs) + len(monotonic_failures) + len(semantic_failures)
    print("\n" + "=" * 72)
    if total_issues == 0:
        print("RESULT: ALL CLEAR — no failures detected")
    else:
        print(f"RESULT: {total_issues} issue(s) found")
        print(f"  Crashes:              {len(crashes)}")
        print(f"  Empty outputs:        {len(empty_outputs)}")
        print(f"  Monotonic violations: {len(monotonic_failures)}")
        print(f"  Semantic failures:    {len(semantic_failures)}")
    print("=" * 72)

    return total_issues


def check_semantic_preservation(original, r1, r2, r3):
    """Heuristic checks that compression doesn't change the meaning."""
    issues = []

    # 1. Negation preservation: if original has a negation, compressed must too
    negation_words = {"not", "no", "don't", "doesn't", "didn't", "can't", "won't",
                      "shouldn't", "wouldn't", "couldn't", "isn't", "aren't",
                      "wasn't", "weren't", "never", "without", "neither",
                      "n't", "prevent", "block", "disable", "reject", "deny",
                      "disabling"}
    orig_lower = original.lower()
    orig_words = set(orig_lower.split())
    orig_has_negation = any(w in orig_words for w in negation_words)

    if orig_has_negation:
        # Check level 3 (most aggressive) — negation must survive
        r3_words = set(r3.lower().split())
        neg_survived = any(
            w in r3_words
            for w in {"not", "no", "n't", "never", "w/o",
                       "prevent", "block", "disable", "reject", "deny",
                       "disabling", "without"}
        ) or "!=" in r3
        if not neg_survived:
            issues.append("negation_lost")

    # 2. Key nouns preservation: important technical nouns should survive
    #    (We check a subset — full NLP would be overkill here)
    import re as _re
    # Extract capitalized or technical terms from the original
    tech_terms = set()
    for word in _re.findall(r'\b[A-Z][a-zA-Z]+\b', original):
        if word.lower() not in {"can", "could", "would", "should", "will",
                                 "please", "the", "this", "that", "with",
                                 "for", "from", "have", "has", "had",
                                 "not", "all", "are", "was", "were", "been",
                                 "being", "but", "just", "also", "very",
                                 "really", "quite", "then", "currently",
                                 "actually", "certainly", "definitely",
                                 "set", "add", "run", "fix", "help",
                                 "build", "write", "create", "implement",
                                 "design", "configure", "check", "review",
                                 "use", "make", "get", "put", "let",
                                 "our", "its", "their", "any", "each",
                                 "every", "both", "these", "those"}:
            tech_terms.add(word)

    # Only flag if a significant proper noun is completely absent from all levels
    for term in tech_terms:
        term_lower = term.lower()
        # Check if the term or a common abbreviation is present
        if (term not in r3 and term_lower not in r3.lower()
                and term[:4].lower() not in r3.lower()):
            # Check known abbreviation mappings
            from caveman.rules import LEVEL2_SUBS
            abbrev = LEVEL2_SUBS.get(term_lower, "")
            if abbrev and abbrev.lower() in r3.lower():
                continue
            # Don't flag very common words that get compressed
            if term_lower in LEVEL2_SUBS:
                continue
            # Only flag proper nouns / product names (2+ uppercase or very specific)
            if sum(1 for c in term if c.isupper()) >= 2 or len(term) > 8:
                if term_lower not in r3.lower():
                    issues.append(f"proper_noun_lost:{term}")

    # 3. Inverted meaning: check if "don't X" becomes just "X" (instruction reversal)
    dont_patterns = [
        (r"(?:don't|do not|never|shouldn't|should not)\s+(\w+)", True),
    ]
    for pat, is_negated in dont_patterns:
        import re as _re2
        matches = _re2.findall(pat, orig_lower)
        for verb in matches:
            # The verb should appear with some negation nearby in L3
            r3_lower = r3.lower()
            verb_pos = r3_lower.find(verb[:4])
            if verb_pos >= 0:
                # Check within 20 chars before the verb for negation
                context_before = r3_lower[max(0, verb_pos - 20):verb_pos]
                if not any(n in context_before for n in {"no", "not", "n't", "never", "w/o"}):
                    # Check if the negation is right after
                    context_after = r3_lower[verb_pos:verb_pos + 20]
                    if "no" not in context_before and "not" not in context_before:
                        pass  # may be an issue but too many false positives

    return issues


if __name__ == "__main__":
    issues = run_regression()
    sys.exit(1 if issues > 0 else 0)
